// // This module decrements the input data by one when enabled and resets to 255
module eth_mac_controller (  
    input wire clk,  
    input wire reset,  
    input wire enable,  
    input wire [7:0] data_in,  
    output reg [7:0] data_out  
);  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            data_out <= 8'b0;  
        end else if (enable) begin  
            data_out <= data_in + 1;  
        end  
    end  
endmodule
